/**
 * Get posts scheduled for a specific date (YYYY-MM-DD)
 */
export function getPostsForDate(date: string): ScheduledPost[] {
  return JUNE_2026_POSTS.filter((post) => post.date === date && !post.published);
}

/**
 * Get all unpublished posts up to and including today
 */
export function getDueUnpublishedPosts(today: string): ScheduledPost[] {
  return JUNE_2026_POSTS.filter((post) => post.date <= today && !post.published);
}

/**
 * Mark a post as published (returns updated array — persist to DB for production use)
 */
export function markPostPublished(id: number, facebookPostId: string): void {
  const post = JUNE_2026_POSTS.find((p) => p.id === id);
  if (post) {
    post.published = true;
    post.publishedAt = new Date().toISOString();
    post.facebookPostId = facebookPostId;
  }
}
